class Solution {
    public int minimumChanges(String s, int k) {
        int n = s.length();
        int[][] dp = new int[n + 1][k + 1];
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= k; j++) {
                dp[i][j] = Integer.MAX_VALUE;
            }
        }
        dp[0][0] = 0;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= Math.min(i, k); j++) {
                for (int d = 1; d < i; d++) {
                    if (i % d == 0) {
                        int changes = 0;
                        for (int group = 0; group < d; group++) {
                            int[] count = new int[26];
                            for (int pos = group; pos < i; pos += d) {
                                count[s.charAt(pos) - 'a']++;
                            }
                            int maxCount = 0;
                            for (int c = 0; c < 26; c++) {
                                maxCount = Math.max(maxCount, count[c]);
                            }
                            changes += count.length - maxCount;
                        }
                        dp[i][j] = Math.min(dp[i][j], dp[i - d][j - 1] + changes);
                    }
                }
            }
        }
        return dp[n][k];
    }
}
